// Vanilla S36PacketSignEditorOpen:
public class S36PacketSignEditorOpen implements Packet<INetHandlerPlayClient> {
    private BlockPos signPosition;
    public S36PacketSignEditorOpen() {}
    public S36PacketSignEditorOpen(BlockPos pos) { this.signPosition = pos; }
    public void processPacket(INetHandlerPlayClient h) { h.handleSignEditorOpen(this); }
    public BlockPos getSignPosition() { return this.signPosition; }
}
